@Service
public class TransferService {

    @Transactional
    public void transfer(Long fromId, Long toId, BigDecimal amount) {
        Account from = accountRepo.findById(fromId)
            .orElseThrow(() -> new NotFoundException("Source account"));
        Account to = accountRepo.findById(toId)
            .orElseThrow(() -> new NotFoundException("Target account"));

        from.debit(amount);
        to.credit(amount);
        // Both saves commit together; exception triggers rollback
    }
}

